#include<bits/stdc++.h>
using namespace std;
char a[1000010],b[1000010];
int nxt[1000010];
int main()
{
    int n;
    scanf("%d%s",&n,a+1);
    int j=0;
    for(int i=2;i<=n;i++)
    {
        while(j>0&&a[i]!=a[j+1])
        {
            j=nxt[j];
        }
        if(a[i]==a[j+1])
        {
            j++;
            nxt[i]=j;
        }
    }
    j=2;
    long long ans=0;
    for(int i=2;i<=n;i++,j=i)
    {
        while(nxt[j])
        {
            j=nxt[j];
        }
        if(nxt[i])
        {
            nxt[i]=j;
        }
        ans+=i-j;
    }
    printf("%lld",ans);
    return 0;
}
